if (typeof _r === 'string') { try { _r = JSON.parse(_r); } catch (e) { _r = {}; } }
const leads = (_r && _r._embedded && _r._embedded.leads) || [];
const TIPO   = {'Piso':'piso','Ático':'atico','Dúplex':'duplex','Chalet':'chalet','Local-Oficina':'local-oficina'};
const EXTRA  = {'Piscina':'piscina','Terraza':'terraza','Jardín':'jardin','Trastero':'trastero','Garaje':'garaje','Ascensor':'ascensor','Exterior':'exterior','Aire acondicionado':'aire'};
const ESTADO = {'Entrar a vivir':'entrar a vivir','A reformar':'a reformar','Obra nueva':'obra nueva'};
const rows = [];
const POOL_STATUSES = new Set([106971083, 105358051, 105358071]); // Ventas / Capacidad de compra / Personal Shopper
for (const l of leads) {
  if (!POOL_STATUSES.has(l.status_id)) continue;            // pool = etapas de busqueda activa (3 embudos)
  const cf = {};
  for (const c of (l.custom_fields_values || [])) cf[c.field_id] = (c.values || []).map(v => v.value);
  const num = (id) => { const v = (cf[id] || [])[0]; return (v === undefined || v === null || v === '') ? null : Number(v); };
  const zonaRaw    = (cf[1373285] || [])[0] || '';
  const municipios = String(zonaRaw).split(',').map(s => s.trim()).filter(Boolean);
  const tipos      = (cf[1376076] || []).map(v => TIPO[v]).filter(Boolean);
  const extras     = (cf[1376080] || []).map(v => EXTRA[v]).filter(Boolean);
  const estados    = (cf[1376082] || []).map(v => ESTADO[v]).filter(Boolean);
  const habRaw     = (cf[1373289] || [])[0] || null;
  const hab_min    = habRaw ? parseInt(String(habRaw), 10) : null;
  const precio_max = num(1376040);
  const precio_min = num(1376044);
  const m2_min     = num(1373287);
  const banos_min  = num(1376078);
  const hasCriteria = municipios.length || tipos.length || extras.length || estados.length ||
                      precio_max != null || precio_min != null || hab_min != null || m2_min != null || banos_min != null;
  if (!hasCriteria) continue;
  const row = { lead_id: Number(l.id), municipios, tipos, precio_max, precio_min, hab_min, m2_min, banos_min, extras, estados };
  row.kommo_hash = JSON.stringify([municipios, tipos, precio_max, precio_min, hab_min, m2_min, banos_min, extras, estados]);
  rows.push(row);
}
return [{ json: { rows, fetch_ok: leads.length > 0 } }];

const items = $input.all();
const results = [];
const opcionesFecha = {timeZone: 'Europe/Madrid', dateStyle: 'full', timeStyle: 'short'};

const AGENT_CALENDARS = {
  ainhoa: 'd23c36eb78a971387b85f2b175348df42eb0bb56a62e08cbe5be715d208232a5@group.calendar.google.com',
  carlos: 'b7e41e1a3aa9a5a4b8d4f9ce1c28cebca78fd7ec1fa6e81f8b056172aae037e5@group.calendar.google.com',
  pedro:  '27f1281a474ac16cd94d55abae17338c73345a16896e18ed854e852d322b795a@group.calendar.google.com',
  ramon:  '5d8f1fa51bd75f41d4521a35393edba14c21c5f257baa698e5959828843a7e82@group.calendar.google.com',
};

function pickCalendar(agenteRaw) {
  const s = (agenteRaw || '').toLowerCase().trim().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  for (const k of Object.keys(AGENT_CALENDARS)) {
    if (s.includes(k)) return { key: k, calendarId: AGENT_CALENDARS[k] };
  }
  return { key: null, calendarId: 'primary' };
}

function cf(customFields, fieldId) {
  if (!Array.isArray(customFields)) return null;
  const f = customFields.find(x => x?.field_id === fieldId);
  return f?.values?.[0]?.value ?? null;
}

for (const item of items) {
  const data = item.json;
  if (!data._embedded || !data._embedded.leads) continue;
  for (const lead of data._embedded.leads) {
    const fields = lead.custom_fields_values || [];
    const ts = cf(fields, 1330871);
    if (!ts) continue;
    const fechaInicio = new Date(Number(ts) * 1000);
    const fechaFin = new Date(fechaInicio.getTime() + 30 * 60 * 1000);

    const agenteName = cf(fields, 1373105);
    const { key: agentKey, calendarId } = pickCalendar(agenteName);

    const direccion = cf(fields, 1373349);
    const idealista_id = cf(fields, 1373305);
    const telefono = (lead.name||'').split('||').map(s=>s.trim()).find(p => p.match(/^\+?\d/)) || '';
    const email = cf(fields, 1372575);

    const _parts = (lead.name||'').split('||').map(s=>s.trim());
    const nombreLimpio = _parts[0] || '';
    const telefonoLimpio = _parts.find(p => p.match(/^\+?\d/)) || '';
    results.push({ json: {
      leadId: lead.id,
      leadName: lead.name,
      nombreLimpio,
      telefonoLimpio,
      agente: agenteName,
      agentKey,
      calendarId,
      email,
      direccion,
      idealista_id,
      telefono,
      diaPreferenciaTimestamp: ts,
      diaPreferenciaFechaFormateada: fechaInicio.toLocaleString('es-ES', opcionesFecha),
      startDate: fechaInicio.toISOString(),
      endDate: fechaFin.toISOString(),
    }});
  }
}
return results;

