const original = $('Set thumbnail_hosted').item.json;
let parsed = {};
try {
  parsed = JSON.parse($json.choices[0].message.content.trim());
} catch (e) { parsed = {}; }
return { json: {
  ...original,
  Direccion: parsed.Direccion || original.Direccion,
  Descripcion: parsed.Descripcion || original.Descripcion
} };

// Recibe N items (uno por propiedad) con campo URL. Emite UN item con
// el array property_urls para enviar al actor Apify en modo detail.
const urls = [];
const seen = new Set();
for (const item of $input.all()) {
  const p = item.json || {};
  const u = p.URL || p.url;
  if (typeof u === 'string' && u && !seen.has(u)) {
    seen.add(u);
    urls.push({ url: u });
  }
}
return [{ json: { property_urls: urls } }];

// Recibe N items, cada uno con el Key devuelto por Storage tras el upload.
// Parsea idealista_id e index del Key y agrupa.
const base = 'https://supabase-simarro.agentesia.madrid/storage/v1/object/public';
const grouped = new Map();

for (const it of $input.all()) {
  const j = it.json || {};
  const key = j.Key || j.key || '';
  const m = String(key).match(/^gallery\/([^/]+)\/(\d+)\.jpg$/);
  if (!m) continue;
  const id = m[1];
  const idx = parseInt(m[2], 10);
  if (!Number.isFinite(idx)) continue;
  if (!grouped.has(id)) grouped.set(id, []);
  grouped.get(id)[idx] = `${base}/${key}`;
}

const out = [];
for (const [id, urls] of grouped.entries()) {
  const clean = urls.filter(Boolean);
  if (clean.length === 0) continue;
  out.push({ json: { idealista_id: id, images_hosted: clean } });
}
return out;

// Recibe la response del actor en modo DETAIL (array de items con multimedia.images[]).
// Emite N×M items con {idealista_id, url, index} para subir al bucket gallery.
const out = [];
for (const it of $input.all()) {
  const arr = Array.isArray(it.json) ? it.json : (Array.isArray(it.json?.body) ? it.json.body : [it.json]);
  for (const item of arr) {
    if (!item || typeof item !== 'object') continue;
    const id = item.adid || item.propertyId || item.propertyCode;
    if (!id) continue;
    const imgs = item.multimedia?.images || [];
    if (!Array.isArray(imgs)) continue;
    imgs.slice(0, 10).forEach((img, index) => {
      const u = img && img.url;
      if (typeof u === 'string' && u) {
        out.push({ json: { idealista_id: String(id), url: u, index } });
      }
    });
  }
}
return out;

