const input = $json;
const idealistaId = (input.idealista_id || '').toString().trim();
let addrContains = (input.address_contains || '').toString().trim();
const query = (input.query || '').toString().trim();
let municipality = (input.municipality || '').toString().trim();
const maxPrice = input.max_price ? Number(input.max_price) : null;
const minPrice = input.min_price ? Number(input.min_price) : null;
const minRooms = input.min_rooms ? Number(input.min_rooms) : null;
const minSize  = input.min_size  ? Number(input.min_size)  : null;
const matchCount = Number(input.match_count) || 5;
const includeNonResidential = input.include_non_residential === true || input.include_non_residential === 'true';

// ASR normalization for Spanish municipality/barrio names
const ZONE_FIX = [
  [/^(las\s+rosas|las\s+rozas(\s+de\s+madrid)?|lasrozas|las\s+roza)$/i, 'Las Rozas'],
  [/^(bajada\s+onda|majada\s+onda|majada\s+honda|majadana|bajadana|majadaonda|mahabonda|majab[oó]n|mahab[oó]n|maja\s+honda|majadaona)$/i, 'Majadahonda'],
  [/^(pozuelo(\s+de\s+alarc[oó]n)?|pozue[ñn]o)$/i, 'Pozuelo'],
  [/^(boadilla(\s+del\s+monte)?)$/i, 'Boadilla del Monte'],
  [/^(villaviciosa(\s+de\s+od[oó]n)?)$/i, 'Villaviciosa de Odón'],
  [/^(san\s+lorenzo(\s+de\s+el\s+escorial)?)$/i, 'San Lorenzo de El Escorial'],
  [/^(rejas?|reposo|rejad[ao])$/i, 'Rejas'],
  [/^(canillejas?)$/i, 'Canillejas'],
  [/^(chamart[ií]n)$/i, 'Chamartín'],
  [/^(chamber[ií])$/i, 'Chamberí'],
  [/^(salamanca|barrio\s+de\s+salamanca)$/i, 'Salamanca'],
  [/^(retiro)$/i, 'Retiro'],
  [/^(arganzuela)$/i, 'Arganzuela'],
  [/^(latina)$/i, 'Latina'],
  [/^(carabanchel)$/i, 'Carabanchel'],
  [/^(usera)$/i, 'Usera'],
  [/^(vallecas|puente\s+de\s+vallecas|villa\s+de\s+vallecas)$/i, 'Vallecas'],
  [/^(moratalaz)$/i, 'Moratalaz'],
  [/^(ciudad\s+lineal)$/i, 'Ciudad Lineal'],
  [/^(hortaleza)$/i, 'Hortaleza'],
  [/^(barajas)$/i, 'Barajas'],
  [/^(san\s+blas|sanblas)$/i, 'San Blas'],
  [/^(tetu[aá]n)$/i, 'Tetuán'],
  [/^(fuencarral|fuencarral-?el\s+pardo|fuencarral\s+el\s+pardo)$/i, 'Fuencarral'],
  [/^(moncloa|moncloa-?aravaca)$/i, 'Moncloa'],
  [/^(centro)$/i, 'Centro'],
];
function fixZone(s) {
  if (!s) return s;
  let t = s.trim();
  // Try full match first (handles "las rosas", "las rozas de madrid")
  for (const [re, val] of ZONE_FIX) if (re.test(t)) return val;
  // Strip trailing comma + city suffix or extra noise
  t = t.replace(/[,;].*$/, '').trim();
  for (const [re, val] of ZONE_FIX) if (re.test(t)) return val;
  // Strip leading articles/prepositions ASR adds, retry
  t = t.replace(/^(en\s+la\s+|en\s+el\s+|en\s+los\s+|en\s+las\s+|en\s+|la\s+|el\s+|los\s+|las\s+|del\s+|de\s+la\s+|de\s+|por\s+la\s+|por\s+el\s+|por\s+|barrio\s+de\s+)/i, '').trim();
  for (const [re, val] of ZONE_FIX) if (re.test(t)) return val;
  return t;
}
addrContains = fixZone(addrContains);
municipality = fixZone(municipality);

let derivedId = idealistaId;
if (!derivedId && /^\d{6,}$/.test(query)) derivedId = query;
if (!derivedId && /idealista\.com\/inmueble\/(\d+)/.test(query)) {
  derivedId = query.match(/idealista\.com\/inmueble\/(\d+)/)[1];
}

const txt = (query + ' ' + addrContains).toLowerCase();
const userAskedNonResi = /\b(local|garaje|trastero|terreno|parcela|nave)\b/.test(txt);
const applyResiFilter = !includeNonResidential && !userAskedNonResi && !derivedId;

const GENERIC_RE = /^(vivienda|viviendas|piso|pisos|casa|casas|chalet|chalets|atico|aticos|ático|áticos|duplex|dúplex|adosado|adosados|pareado|pareados|inmueble|inmuebles|propiedad|propiedades|algo|nada|lo\s+que\s+(tengas|haya|sea))\.?$/i;
const isGenericQuery = !!query && GENERIC_RE.test(query.trim());
const hasAnyFilter = addrContains || maxPrice || minPrice || minRooms || minSize || municipality;

// Try to extract a known zone word from the query — if any token matches our zone dictionary,
// promote it to address_contains and prefer byFilter over semantic.
function findZoneInQuery(q) {
  if (!q) return null;
  const tokens = q.toLowerCase().split(/[\s,;]+/).filter(Boolean);
  // Try 1-3 token windows
  for (let len = 3; len >= 1; len--) {
    for (let i = 0; i + len <= tokens.length; i++) {
      const window = tokens.slice(i, i+len).join(' ');
      for (const [re, val] of ZONE_FIX) if (re.test(window)) return val;
    }
  }
  return null;
}
if (!addrContains && !municipality && query && !derivedId) {
  const zoneFromQuery = findZoneInQuery(query);
  if (zoneFromQuery) {
    addrContains = zoneFromQuery;
  }
}
const hasAnyFilter2 = addrContains || maxPrice || minPrice || minRooms || minSize || municipality;

let path;
if (derivedId) {
  path = 'byId';
} else if (isGenericQuery && !hasAnyFilter2) {
  path = 'browse';
} else if (!query && !hasAnyFilter2) {
  path = 'empty';
} else {
  const wordCount = query.split(/\s+/).filter(w => w.match(/[a-záéíóúüñ]/i)).length;
  // Prefer byFilter when we have a zone (address_contains or municipality) — semantic only for genuinely long descriptive queries with NO zone
  if (hasAnyFilter2 && wordCount < 6) path = 'byFilter';
  else if (wordCount >= 4) path = 'semantic';
  else path = 'byFilter';
}

function resiClause(parts) {
  if (applyResiFilter) {
    parts.push(`address=not.ilike.Local*`);
    parts.push(`address=not.ilike.Garaje*`);
    parts.push(`address=not.ilike.Trastero*`);
    parts.push(`address=not.ilike.Terreno*`);
    parts.push(`address=not.ilike.Nave*`);
    parts.push(`address=not.ilike.Parcela*`);
  }
}

let pgrestQuery = '';
if (path === 'byId') {
  pgrestQuery = `?idealista_id=eq.${encodeURIComponent(derivedId)}&select=*&limit=1`;
} else if (path === 'browse') {
  const parts = ['select=*'];
  resiClause(parts);
  parts.push(`limit=${Math.max(matchCount, 25)}`);
  pgrestQuery = '?' + parts.join('&');
} else if (path === 'byFilter') {
  const parts = ['select=*'];
  const zoneFrag = addrContains || municipality || (query && !derivedId && !isGenericQuery ? fixZone(query) : '');
  if (zoneFrag) {
    const enc = encodeURIComponent(zoneFrag);
    parts.push(`or=(address.ilike.*${enc}*,municipality.ilike.*${enc}*)`);
  }
  if (maxPrice) parts.push(`price=lte.${maxPrice}`);
  if (minPrice) parts.push(`price=gte.${minPrice}`);
  if (minRooms) parts.push(`rooms=gte.${minRooms}`);
  if (minSize)  parts.push(`size_m2=gte.${minSize}`);
  resiClause(parts);
  parts.push(`limit=${matchCount}`);
  pgrestQuery = '?' + parts.join('&');
}

return [{ json: {
  path, pgrestQuery, derivedId, applyResiFilter,
  query, municipality: municipality || null, address_contains: addrContains || null,
  max_price: maxPrice, min_price: minPrice, min_rooms: minRooms, min_size: minSize,
  match_count: matchCount, exclude_ids: input.exclude_ids || [],
}}];

