try {
  const routerOut = $('Router').first().json;
  if (routerOut && routerOut.path === 'empty') {
    return [{ json: { found: 0, message: 'Necesito al menos un criterio (zona, presupuesto, características o referencia). ¿Qué buscas?', results: [], catalogo_compacto: [], zones: [] } }];
  }
} catch (e) {}

const items = $input.all();
const rows = [];
for (const i of items) {
  if (Array.isArray(i.json)) rows.push(...i.json);
  else if (i.json && (i.json.idealista_id || i.json.id || i.json.address)) rows.push(i.json);
}

let excludeIds = [];
try {
  const ex = $('Router').first().json.exclude_ids;
  excludeIds = Array.isArray(ex) ? ex : (typeof ex === 'string' ? JSON.parse(ex || '[]') : []);
} catch (e) { excludeIds = []; }

let applyResi = false;
try { applyResi = !!$('Router').first().json.applyResiFilter; } catch (e) {}

const filtered = rows.filter(r => {
  if (excludeIds.includes(String(r.idealista_id))) return false;
  if (applyResi && r.address) {
    if (/^(local|garaje|trastero|terreno|nave|parcela|edificio)\b/i.test(r.address)) return false;
  }
  return true;
});

if (!filtered.length) {
  return [{ json: { found: 0, message: 'No se encontraron viviendas que coincidan con esos criterios.', results: [], catalogo_compacto: [], zones: [] } }];
}

const formatted = filtered.map(r => ({
  idealista_id: r.idealista_id,
  url: r.url,
  precio: r.price,
  direccion: r.address,
  municipio: r.municipality,
  habitaciones: r.rooms,
  banos: r.bathrooms,
  m2: r.size_m2,
  thumbnail: r.thumbnail_hosted || (r.idealista_id ? 'http://simarro-pre0225supabase-f93ff3-185-47-13-169.traefik.me/storage/v1/object/public/thumbnails/' + r.idealista_id + '.jpg' : r.thumbnail),
  similitud: r.similarity ? Math.round(r.similarity * 100) / 100 : null,
  descripcion: (r.description || '').slice(0, 300),
  descripcion_corta: (r.description || '').slice(0, 100),
}));

const zoneCounts = {};
formatted.forEach(p => { const m = p.municipio || 'sin zona'; zoneCounts[m] = (zoneCounts[m] || 0) + 1; });
const zones = Object.entries(zoneCounts).map(([m, c]) => ({ municipio: m, count: c }));

const compacto = formatted.map(p => ({
  id: p.idealista_id,
  zona: p.municipio,
  direccion: p.direccion,
  precio: p.precio,
  habs: p.habitaciones,
  m2: p.m2,
  banos: p.banos,
  desc: p.descripcion_corta,
}));

const summary = formatted.map((p, i) =>
  `${i+1}. ${p.direccion || 'Dirección desconocida'} (${p.municipio || '?'}) — ${p.precio ? p.precio.toLocaleString('es-ES') + '€' : 'precio ?'} · ${p.habitaciones || '?'}h · ${p.m2 || '?'}m² · ID ${p.idealista_id}`
).join('\n');

return [{ json: { found: formatted.length, message: summary, results: formatted, catalogo_compacto: compacto, zones } }];

const r = $('Format For Agent').first().json;
let ro={}; try{ ro=$('Router').first().json||{}; }catch(e){}
if (ro.path === 'empty') return [{ json: r }];
const CLUSTER=new Set(['pozuelo','pozuelo de alarcon','majadahonda','las rozas','las rozas de madrid','boadilla del monte','villaviciosa de odon','madrid']);
const norm=s=>(s||'').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').trim();
let cat=[]; try{ cat=$('Get Catálogo').all().map(i=>i.json).filter(x=>x&&!Array.isArray(x)&&x.municipality); }catch(e){ cat=[]; }
const maxP=ro.max_price||null,minP=ro.min_price||null,minR=ro.min_rooms||null,minS=ro.min_size||null,resi=!!ro.applyResiFilter;
const asked=ro.address_contains||ro.municipality||null; const counts={};
for(const p of cat){ const m=p.municipality;
  if(asked&&norm(m)===norm(asked))continue;
  if(resi&&p.address&&/^(local|garaje|trastero|terreno|nave|parcela|edificio)\b/i.test(p.address))continue;
  if(maxP&&p.price!=null&&Number(p.price)>maxP)continue;
  if(minP&&p.price!=null&&Number(p.price)<minP)continue;
  if(minR&&p.rooms!=null&&Number(p.rooms)<minR)continue;
  if(minS&&p.size_m2!=null&&Number(p.size_m2)<minS)continue;
  if(!CLUSTER.has(norm(m)))continue;
  counts[m]=(counts[m]||0)+1; }
const zones=Object.entries(counts).map(([municipio,count])=>({municipio,count})).sort((a,b)=>b.count-a.count);
const zt=zones.map(z=>z.municipio).join(', ');
const message=zones.length?('No hay nada en esa zona con esos criterios. Donde si hay viviendas que encajan ahora mismo: '+zt+'.'):r.message;
return [{ json: { ...r, message, zones } }];

