function splitAddress(s){if(!s||typeof s!=='string') return {calle:'',municipio:''};s=s.trim();s=s.replace(/^(chalet|piso|ático|atico|casa|apartamento|estudio|dúplex|duplex|loft|adosado|pareado)\s+en\s+/i,'');const cp=s.match(/\b(\d{5})\b/);if(!cp) return {calle:s.replace(/[,\s]+$/,'').trim(),municipio:''};const before=s.slice(0,cp.index).replace(/[,\s]+$/,'').trim();const after=s.slice(cp.index+5).replace(/^[,\s]+/,'').trim();return {calle:before.split(',')[0].trim(),municipio:after.split(',')[0].replace(/^de\s+/i,'').trim()};}

let fechaHablable = null;
let fechaIso = null;
if (fechaCitaSec && Number(fechaCitaSec) > 0) {
  const d = new Date(Number(fechaCitaSec) * 1000);
  const fmt = new Intl.DateTimeFormat('es-ES', {timeZone:'Europe/Madrid', weekday:'long', year:'numeric', month:'2-digit', day:'2-digit', hour:'2-digit', minute:'2-digit', hour12:false});
  const p = fmt.formatToParts(d).reduce((a,x)=>{a[x.type]=x.value;return a;},{});
  const y=+p.year, mo=+p.month, day=+p.day, h=+p.hour, mi=+p.minute;
  const weekday = (p.weekday||'').toLowerCase();
  fechaHablable = `${weekday} ${numberToWords(day)} ${timeToWords(h,mi)} ${dayPart(h)}`;
  fechaIso = d.toISOString();
}

const {calle, municipio} = splitAddress(direccion);
