// Filtra leads elegibles para llamada de reactivación.
// Reglas: consentimiento outbound (CF 1376604) marcado + intentos (CF 1376606) < 3
//         + >= 10 días desde el último intento (CF 1376608) o, si nunca se llamó,
//           desde la última actividad del lead (updated_at).
// El schedule corre L-V => lo vencido en sábado/domingo se llama el lunes (sin lógica extra).
// TODO Lista Robinson: documentado y pospuesto por decisión de Manu 2026-06-10 — antes de
// escalar volumen, cruzar los teléfonos contra la Lista Robinson (asesoría/servicio externo).
const CF_CONSENT = 1376604, CF_INTENTOS = 1376606, CF_ULTIMO = 1376608;
const CF_VIV_DIR = 1373349, CF_PROP_REF = 1373305;
const DIAS_MIN = 10, MAX_INTENTOS = 3;

let data = $json.data ?? $json;
if (typeof data === 'string') { try { data = JSON.parse(data); } catch(e) { data = {}; } }
const leads = data?._embedded?.leads ?? [];

const cf = (lead, id) => {
  const f = (lead.custom_fields_values || []).find(x => x.field_id === id);
  return f?.values?.[0]?.value;
};
const truthy = v => v === true || v === 'true' || v === 1 || v === '1';
const toMs = v => {
  if (v == null || v === '') return null;
  if (typeof v === 'number') return v * 1000;
  const n = Number(v);
  if (!isNaN(n) && n > 1000000000) return n * 1000;
  const d = Date.parse(v);
  return isNaN(d) ? null : d;
};

const now = Date.now();
const out = [];
for (const lead of leads) {
  if (!truthy(cf(lead, CF_CONSENT))) continue;                 // sin consentimiento => fuera
  const intentos = parseInt(cf(lead, CF_INTENTOS) || '0', 10) || 0;
  if (intentos >= MAX_INTENTOS) continue;                       // cap de intentos
  const ultimoMs = toMs(cf(lead, CF_ULTIMO));
  const refMs = ultimoMs ?? (lead.updated_at ? lead.updated_at * 1000 : null);
  if (refMs == null) continue;
  const dias = Math.floor((now - refMs) / 86400000);
  if (dias < DIAS_MIN) continue;                                // aún no toca

  const contacts = lead._embedded?.contacts || [];
  const main = contacts.find(c => c.is_main) || contacts[0];
  if (!main?.id) continue;                                      // sin contacto => no se puede llamar

  out.push({ json: {
    lead_id: lead.id,
    lead_name: lead.name || '',
    contact_id: main.id,
    attempt: intentos + 1,
    dias_inactivo: dias,
    vivienda_dir: String(cf(lead, CF_VIV_DIR) || ''),
    vivienda_idealista_id: String(cf(lead, CF_PROP_REF) || ''),
  }});
}
return out;

// Cruza el contacto (item actual) con su lead (Filtrar elegibles, mismo índice).
// Normaliza el teléfono a E.164 (+34...) y descarta leads sin móvil llamable.
const out = [];
for (let i = 0; i < items.length; i++) {
  let c = items[i].json.data ?? items[i].json;
  if (typeof c === 'string') { try { c = JSON.parse(c); } catch(e) { c = {}; } }
  const lead = $('Filtrar elegibles').all()[i].json;

  const phoneField = (c.custom_fields_values || []).find(f => f.field_code === 'PHONE');
  let raw = String(phoneField?.values?.[0]?.value || '').replace(/[\s\-().]/g, '');
  if (!raw) continue;
  if (raw.startsWith('00')) raw = '+' + raw.slice(2);
  if (!raw.startsWith('+')) {
    if (/^34\d{9}$/.test(raw)) raw = '+' + raw;
    else if (/^\d{9}$/.test(raw)) raw = '+34' + raw;
    else continue; // formato no reconocido => no llamar
  }
  if (!/^\+\d{10,15}$/.test(raw)) continue;

  const nombre = (c.first_name || c.name || lead.lead_name || '').trim().split(/\s+/)[0] || 'cliente';

  out.push({ json: { ...lead, phone: raw, nombre_lead: nombre } });
}
return out;

// Cruza el lead del Loop (batch=1) con los resultados de match_pairs.
// Elige como ALTERNATIVA la mejor vivienda que case con su perfil y NO sea
// la que ya le interesaba (vivienda_idealista_id). Criterio: la mas barata.
// Si la RPC fallo o no hay perfil/matches => vars de match vacias (el flow degrada solo).
