  let j = it.json.data ?? it.json;
  if (typeof j === 'string') { try { j = JSON.parse(j); } catch(e) { j = null; } }
  if (Array.isArray(j)) matches.push(...j);
  else if (j && j.idealista_id) matches.push(j);
}
const orig = String(lead.vivienda_idealista_id || '');
const alt = matches
  .filter(m => m && m.idealista_id && String(m.idealista_id) !== orig)
  .sort((a, b) => (Number(a.price) || 9e9) - (Number(b.price) || 9e9))[0] || null;

return [{ json: { ...lead,
  vivienda_match_id:     alt ? String(alt.idealista_id) : '',
  vivienda_match_dir:    alt ? [alt.address, alt.municipality].filter(Boolean).join(', ') : '',
  vivienda_match_precio: alt && alt.price ? String(Math.round(Number(alt.price))) : '',
  vivienda_match_tipo:   alt ? String(alt.property_type || '') : '',
}}];

