// Calc_Disponibilidad — single source of truth del cálculo de huecos de visita.
// Visitas de 1h, horario L-V 10:00-14:00 y 17:00-20:00 (Europe/Madrid).
// Buffer entre visitas del mismo calendario: 0 si MISMA vivienda, 30min si DISTINTA (simétrico).
// Default restrictivo: si no se puede parsear el idealista_id de un evento => se trata como DISTINTA (30min).
//
// Input (un único item):
//   { modo:'listar'|'validar', start, end, idealista_id, eventos:[{start,end,summary}] }
//   - listar: devuelve { libre, finDeSemana, slots[], slots_cronologico[], fecha, mensaje }
//   - validar: 'start' es el inicio EXACTO pedido; devuelve { libre, motivo, alternativas[], fecha }
const p = ($input.first() && $input.first().json) ? $input.first().json : {};
const modo = (p.modo || 'listar').toString();
const consultaIdealista = (p.idealista_id || '').toString().trim();
const eventos = Array.isArray(p.eventos) ? p.eventos : [];

const TZ = 'Europe/Madrid';
const BUFFER_DISTINTA_MIN = 60;
const VISITA_MIN = 30;
const MS = 60000;
const TRAMOS = [{ ini: 10, fin: 14 }, { ini: 17, fin: 20 }]; // último inicio = fin-1 (13:00, 19:00)

// --- Helpers de zona horaria Madrid (sin libs; offset real por instante => DST-safe) ---
function partsTZ(date) {
  return new Intl.DateTimeFormat('en-CA', {
    timeZone: TZ, year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false, weekday: 'short'
  }).formatToParts(date).reduce((a, x) => (a[x.type] = x.value, a), {});
}
function offsetMs(date) {
  const q = partsTZ(date);
  return Date.UTC(+q.year, +q.month - 1, +q.day, +q.hour, +q.minute, +q.second) - date.getTime();
}
// Date correspondiente a la hora local Madrid (hh:mm) del MISMO día que `base`
function madridDate(base, hh, mm) {
  const q = partsTZ(base);
  let guess = Date.UTC(+q.year, +q.month - 1, +q.day, hh, mm, 0) - offsetMs(base);
  guess = Date.UTC(+q.year, +q.month - 1, +q.day, hh, mm, 0) - offsetMs(new Date(guess));
  return new Date(guess);
}

const parseId = (s) => { if (!s) return ''; const arr = String(s).split(' — '); return (arr[2] || '').trim(); };
const overlaps = (aI, aF, bI, bF) => aI < bF && bI < aF; // intervalos semiabiertos

// Bloqueos con buffer aplicado a ambos bordes
function buildBloqueos() {
  return eventos.filter(e => e && e.start).map(ev => {
    const s = new Date(ev.start.dateTime || ev.start.date || ev.start);
    const e = new Date(ev.end.dateTime || ev.end.date || ev.end);
    const evId = parseId(ev.summary);
    const misma = !!(consultaIdealista && evId && evId === consultaIdealista);
    const bufMs = (misma ? 0 : BUFFER_DISTINTA_MIN) * MS;
    return { sBuf: new Date(s.getTime() - bufMs), eBuf: new Date(e.getTime() + bufMs) };
  });
}

const startDate = new Date(p.start);
const endDate = new Date(p.end || p.start);
// GUARDA: input sin fecha o inválido => no petar (antes lanzaba "Invalid time value").
if (!p.start || isNaN(startDate.getTime())) {
  if (modo === 'validar') return [{ json: { libre: false, motivo: 'sin_fecha', alternativas: [], fecha: null } }];
  return [{ json: { libre: false, finDeSemana: false, slots: [], slots_cronologico: [], fecha: null, error: 'sin_fecha', mensaje: 'No me ha llegado la fecha a consultar. ¿Qué día te viene bien?' } }];
}
const refParts = partsTZ(startDate);
const finDeSemana = (refParts.weekday === 'Sat' || refParts.weekday === 'Sun');
const fechaLargaES = new Intl.DateTimeFormat('es-ES', { timeZone: TZ, weekday: 'long', day: 'numeric', month: 'long' }).format(startDate);
const hhmm = (d) => new Intl.DateTimeFormat('es-ES', { timeZone: TZ, hour: '2-digit', minute: '2-digit', hour12: false }).format(d);
const ahora = new Date();
const blk = buildBloqueos();

function slotLibre(ini) {
  const fin = new Date(ini.getTime() + VISITA_MIN * MS);
  if (fin <= ahora) return false; // no ofrecer huecos ya vencidos
  return !blk.some(b => overlaps(ini, fin, b.sBuf, b.eBuf));
}

function generarSlots() {
  const out = [];
  if (finDeSemana) return out;
  for (const t of TRAMOS) {
    // inicios cada 30 min (:00 y :30) que dejen caber la visita completa dentro del tramo
    for (let mins = t.ini * 60; mins + VISITA_MIN <= t.fin * 60; mins += 30) {
      const ini = madridDate(startDate, Math.floor(mins / 60), mins % 60);
      out.push({ ini, hhmm: hhmm(ini), libre: slotLibre(ini) });
    }
  }
  return out;
}

if (modo === 'validar') {
  const ini = startDate;
  const fin = new Date(ini.getTime() + VISITA_MIN * MS);
  const ip = partsTZ(ini);
  const h = +ip.hour, m = +ip.minute;
  const enTramo = (m === 0 || m === 30) && TRAMOS.some(t => { const s = h * 60 + m; return s >= t.ini * 60 && s + VISITA_MIN <= t.fin * 60; });
  let motivo = null;
  if (finDeSemana) motivo = 'fin_de_semana';
  else if (!enTramo) motivo = 'fuera_horario';
  else if (fin <= ahora) motivo = 'pasado';
  else if (blk.some(b => overlaps(ini, fin, b.sBuf, b.eBuf))) motivo = 'slot_ocupado';
  const libre = motivo === null;
  let alternativas = [];
  if (!libre && !finDeSemana) {
    alternativas = generarSlots().filter(s => s.libre).map(s => s.hhmm).sort();
  }
  return [{ json: { libre, motivo, alternativas, fecha: fechaLargaES } }];
}

// modo === 'listar'
const all = generarSlots();
const libresArr = all.filter(s => s.libre);
const centro = (startDate.getTime() + endDate.getTime()) / 2;
libresArr.sort((a, b) => Math.abs(a.ini.getTime() - centro) - Math.abs(b.ini.getTime() - centro));
const slots = libresArr.map(s => s.hhmm);                       // priorizados por cercanía a lo pedido
const slotsCron = all.filter(s => s.libre).map(s => s.hhmm).sort(); // cronológico para el mensaje
const libre = slots.length > 0;
let mensaje;
if (finDeSemana) mensaje = `El ${fechaLargaES} no atendemos visitas (es fin de semana). ¿Te viene bien un día laborable?`;
else if (!libre) mensaje = `Para el ${fechaLargaES} no me queda ningún hueco de una hora. ¿Probamos otro día?`;
else mensaje = `Para el ${fechaLargaES} tengo libre a las ${slotsCron.join(', a las ')}.`;
return [{ json: { libre, finDeSemana, slots, slots_cronologico: slotsCron, fecha: fechaLargaES, mensaje } }];

