if (tipoContrato === 'promesa_compraventa') required = [...REQUIRED_PROMESA_BASE];
else if (tipoContrato === 'promesa_supeditada') required = [...REQUIRED_PROMESA_BASE, ...REQUIRED_SUPEDITADA_EXTRA];
else if (tipoContrato === 'encargo_agente_unico') required = [...REQUIRED_ENCARGO_BASE];
