const ef3 = $('Edit Fields3').item.json;
const leadResp = $input.first().json;
const leadId = leadResp._embedded.leads[0].id;
// Si hay contacto previo con lead WA, usar ese lead para el salesbot (tiene conversación WA)
let salesbotLeadId = leadId;
try {
  const contactData = $('Code in JavaScript1').item.json;
  const pc = contactData && contactData.primer_contacto;
  if (pc && pc._embedded && Array.isArray(pc._embedded.leads) && pc._embedded.leads.length > 0) {
    salesbotLeadId = pc._embedded.leads[0].id;
  }
} catch(e) {}

const fechaStr = ef3['Fecha preferida'];
let fecha;
if (!fechaStr) throw new Error('Fecha preferida vacía');
if (fechaStr.includes('+') || fechaStr.includes('Z')) {
  fecha = new Date(fechaStr);
} else {
  const mes = new Date(fechaStr).getMonth();
  const offset = (mes >= 2 && mes <= 9) ? '+02:00' : '+01:00';
  fecha = new Date(fechaStr + offset);
}
const segundos = Math.floor(fecha.getTime() / 1000);
const fechaInicioISO = fecha.toISOString();
const fechaFin = new Date(fecha.getTime() + 30 * 60 * 1000);
const fechaFinISO = fechaFin.toISOString();
const fechaInicioMadrid = fecha.toLocaleString('es-ES', {
  timeZone: 'Europe/Madrid', weekday: 'long', year: 'numeric',
  month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit'
});
return [{ json: {
  leadId,
  salesbotLeadId,
  nombre: ef3.nombre || '',
  telefono: ef3.telefono || ef3['numero de telefono'] || '',
  idealista_id: ef3.idealista_id || '',
  direccion: ef3.direccion || '',
