function numberToWords(n) {
  const map = {1:'uno',2:'dos',3:'tres',4:'cuatro',5:'cinco',6:'seis',7:'siete',8:'ocho',9:'nueve',
    10:'diez',11:'once',12:'doce',13:'trece',14:'catorce',15:'quince',16:'dieciséis',17:'diecisiete',
    18:'dieciocho',19:'diecinueve',20:'veinte',21:'veintiuno',22:'veintidós',23:'veintitrés',
    24:'veinticuatro',25:'veinticinco',26:'veintiséis',27:'veintisiete',28:'veintiocho',29:'veintinueve',
    30:'treinta',31:'treinta y uno'};
  return map[n] || String(n);
}
function hourWord(h){const m={1:'una',2:'dos',3:'tres',4:'cuatro',5:'cinco',6:'seis',7:'siete',8:'ocho',9:'nueve',10:'diez',11:'once',12:'doce'};return m[h];}
function minuteWord(m){
  const u=['','uno','dos','tres','cuatro','cinco','seis','siete','ocho','nueve'];
  const t={10:'diez',11:'once',12:'doce',13:'trece',14:'catorce',16:'dieciséis',17:'diecisiete',18:'dieciocho',19:'diecinueve',20:'veinte',21:'veintiuno',22:'veintidós',23:'veintitrés',24:'veinticuatro',25:'veinticinco',26:'veintiséis',27:'veintisiete',28:'veintiocho',29:'veintinueve'};
  if(m<10) return u[m];
  return t[m]||String(m);
}
function timeToWords(h24,m){
  let h=h24%12;
