// Obtener los datos del nodo anterior "Get list of contacts"
const contacts = $input.all();

// Inicializar variables
let existeContacto = false;
let primerContacto = null;

// Verificar si hay datos en la respuesta
if (contacts.length > 0) {
  const data = contacts[0].json;

  // Validar estructura del JSON
  if (data && data._embedded && Array.isArray(data._embedded.contacts)) {
    const listaContactos = data._embedded.contacts;

    // Verificar si existe algún contacto con ID válido
    if (listaContactos.length > 0) {
      const contactoConID = listaContactos.find(c => c.id && typeof c.id === 'number');
      if (contactoConID) {
        existeContacto = true;
        primerContacto = contactoConID;
      }
    }
  }
}

// Retornar resultado
return [{
  json: {
    existe_contacto: existeContacto,
    cantidad_contactos: primerContacto ? 1 : 0,
    primer_contacto: primerContacto
  }
}];

