    24:'veinticuatro',25:'veinticinco',26:'veintiséis',27:'veintisiete',28:'veintiocho',29:'veintinueve',
    30:'treinta',31:'treinta y uno'};
  return map[n] || String(n);
}
function hourWord(h){const m={1:'una',2:'dos',3:'tres',4:'cuatro',5:'cinco',6:'seis',7:'siete',8:'ocho',9:'nueve',10:'diez',11:'once',12:'doce'};return m[h];}
function minuteWord(m){
  const u=['','uno','dos','tres','cuatro','cinco','seis','siete','ocho','nueve'];
