if (!lead_id && body.leads && body.leads.status) {
  const change = Array.isArray(body.leads.status) ? body.leads.status[0] : body.leads.status['0'] || body.leads.status;
  if (change) {
    lead_id = change.id || change.lead_id;
    status_id = Number(change.status_id);
  }
}

if (!lead_id) {
  return [{ json: { skip: true, reason: 'no lead_id in payload' } }];
}

