    has_buyer_phone: Boolean(buyer_phone),
    has_vendor_phone: Boolean(vendor_phone),
  }
}];

const lead = $('Unpack Lead').first().json;
const cfvMap = {};
for (const cfv of (lead.custom_fields_values || [])) {
  const v = cfv.values && cfv.values[0] && cfv.values[0].value;
  cfvMap[cfv.field_id] = v;
}
const url = cfvMap[1375862] || '';
const m = url.match(/\/file\/d\/([a-zA-Z0-9_-]+)/);
if (!m) {
  return [{ json: { error: 'borrador PDF URL no parseable', url, lead_id: lead.id, raw_lead: lead } }];
}
return [{ json: { fileId: m[1], borrador_url: url, lead_id: lead.id, raw_lead: lead } }];

// SIMARRO_SIGNER: firmante de la agencia para encargos + hoja de visita.
// Producción: cuenta real con la que firma Simarro (consultingsimarroproperties@gmail.com).
const SIMARRO_SIGNER = { email: 'consultingsimarroproperties@gmail.com', name: 'Consulting Simarro Properties SL' };

const lead = $('Unpack Lead').first().json;
const docId = $input.first().json.id;
const cfvMap = {};
for (const cfv of (lead.custom_fields_values || [])) {
  const v = cfv.values && cfv.values[0] && cfv.values[0].value;
  cfvMap[cfv.field_id] = v;
}
const tipo = cfvMap[1375840];
const cleanName = String(lead.name || '').replace(/^contrato\s*[—–-]+\s*/i, '');
let recipients = [];
if (tipo && tipo.indexOf('encargo') === 0) {
  // Propietario(s) + Simarro (sin vendedor aparte)
  const email1 = cfvMap[1375870];
  recipients.push({ email: email1, name: cleanName || 'Propietario', role: 'SIGNER', signingOrder: 1 });
  const nombre2 = cfvMap[1376494];
  const email2 = cfvMap[1376498] || email1;
  if (nombre2) recipients.push({ email: email2, name: nombre2, role: 'SIGNER', signingOrder: 2 });
  recipients.push({ email: SIMARRO_SIGNER.email, name: SIMARRO_SIGNER.name, role: 'SIGNER', signingOrder: recipients.length + 1 });
} else if (tipo === 'hoja_visita') {
  // Visitante(s) C1 (+C2) + Simarro
  const email1 = cfvMap[1375860];
  recipients.push({ email: email1, name: cleanName || 'Cliente', role: 'SIGNER', signingOrder: 1 });
  const nombre2 = cfvMap[1376378];
  const email2 = cfvMap[1376504] || email1;
  if (nombre2) recipients.push({ email: email2, name: nombre2, role: 'SIGNER', signingOrder: 2 });
  recipients.push({ email: SIMARRO_SIGNER.email, name: SIMARRO_SIGNER.name, role: 'SIGNER', signingOrder: recipients.length + 1 });
} else {
  // Promesas: comprador (+C2) + vendedor (sin Simarro)
  const emailComprador = cfvMap[1375860];
  const nombreComprador2 = cfvMap[1376378];
  const emailVendedor = cfvMap[1375870];
  const nombreVendedor = cfvMap[1375854] || 'Vendedor';
  recipients.push({ email: emailComprador, name: cleanName || 'Comprador', role: 'SIGNER', signingOrder: 1 });
  const emailComprador2 = cfvMap[1376504] || emailComprador;
  if (nombreComprador2) recipients.push({ email: emailComprador2, name: nombreComprador2, role: 'SIGNER', signingOrder: 2 });
  recipients.push({ email: emailVendedor, name: nombreVendedor, role: 'SIGNER', signingOrder: recipients.length + 1 });
}
return [{ json: { documentId: docId, envelopeId: $input.first().json.envelopeId, tipo, recipientsPayload: { documentId: docId, recipients } } }];

const docId = $('Documenso Build Recipients').first().json.documentId;
const tipo = $('Documenso Build Recipients').first().json.tipo;
const recipients = $input.first().json.recipients || [];
const lastPage = ($('Count Pages').first().json.pageCount) || 2;
const sorted = [...recipients].sort((a, b) => (a.signingOrder || 0) - (b.signingOrder || 0));
const fields = [];
function add(r, page, x, ySig, yDate) {
  fields.push({ recipientId: r.id, type: 'SIGNATURE', pageNumber: page, pageX: x, pageY: ySig,  width: 22, height: 6 });
  fields.push({ recipientId: r.id, type: 'DATE',      pageNumber: page, pageX: x, pageY: yDate, width: 22, height: 3 });
}
if (tipo && (tipo.indexOf('encargo') === 0 || tipo === 'hoja_visita')) {
  // Cliente(s) a la izquierda (apilados); Simarro (último) a la derecha. FDO en última página.
  const base = 64;
  for (let i = 0; i < sorted.length; i++) {
    const r = sorted[i];
    const isSimarro = (i === sorted.length - 1);
    if (isSimarro) add(r, lastPage, 55, base, base + 6);
    else add(r, lastPage, 12, base + i * 12, base + i * 12 + 6);
  }
} else {
  // Promesas
  const P2 = [{ x: 10, ySig: 70, yDate: 77 }, { x: 55, ySig: 70, yDate: 77 }];
  const P3 = [{ x: 10, ySig: 70, yDate: 77 }, { x: 10, ySig: 82, yDate: 89 }, { x: 55, ySig: 70, yDate: 77 }];
  const positions = sorted.length <= 2 ? P2 : P3;
  for (let i = 0; i < sorted.length; i++) { const r = sorted[i]; const p = positions[i] || positions[positions.length - 1]; add(r, lastPage, p.x, p.ySig, p.yDate); }
}
return [{ json: { documentId: docId, fieldsPayload: { documentId: docId, fields }, recipients } }];

