// Build a shape compatible with the rest of the workflow (Build Email HTML, Build Custom Fields Update)
const distRes = $input.first().json;
const recipients = $('Documenso Create Recipients').first().json.recipients || [];
const docId = $('Documenso Build Recipients').first().json.documentId;
const envelopeId = $('Documenso Build Recipients').first().json.envelopeId;
const baseUrl = 'https://documenso-simarro.agentesialabs.com/sign';
// recipients order: c1 (signingOrder=1), maybe c2, vendedor (last)
const byOrder = [...recipients].sort((a,b) => (a.signingOrder||0) - (b.signingOrder||0));
const c1   = byOrder[0] || null;
const last = byOrder[byOrder.length - 1] || null;
const c2   = byOrder.length === 3 ? byOrder[1] : null;
function urlOf(r){ return r ? `${baseUrl}/${r.token}` : null; }
return [{ json: {
  submission_id: envelopeId,
  document_id: docId,
  lead_id:   $('Extract Drive FileId').first().json.lead_id,
  lead_name: $('Unpack Lead').first().json.name,
  submitters: {
    Vendedor:   { id: last && last.id, email: last && last.email, url: urlOf(last) },
    Comprador:  { id: c1 && c1.id,    email: c1 && c1.email,    url: urlOf(c1) },
    Comprador2: c2 ? { id: c2.id, email: c2.email, url: urlOf(c2) } : null,
  }
} }];

const leadId = $('Parse Kommo Payload').first().json.lead_id;
const ext = 'lead-' + leadId;
const resp = $input.first().json || {};
const docs = resp.documents || resp.data || (Array.isArray(resp) ? resp : []);
const ACTIVE = ['DRAFT', 'PENDING', 'COMPLETED'];
const existing = (docs || []).filter(d =>
  d && d.externalId === ext && ACTIVE.includes(String(d.status || '').toUpperCase())
);
const lead = $('Unpack Lead').first().json;
return [{ json: Object.assign({}, lead, { _doc_exists: existing.length > 0, _existing_doc_ids: existing.map(d => d.id) }) }];

const items = $input.all();
let pageCount = 2;
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  const txt = buf.toString('latin1');
  const m = txt.match(/\/Type\s*\/Page[^s]/g);
  if (m && m.length) pageCount = m.length;
} catch (e) {}
return [{ json: Object.assign({}, items[0].json, { pageCount }), binary: items[0].binary }];

// Reutilizar contacto existente si su PHONE coincide con el tel del vendedor (últimos 9 dígitos)
const phone = String($('Build Custom Fields Update').first().json.vendor.phone || '');
const want = phone.replace(/\D/g, '').slice(-9);
const res = $input.first().json || {};
const list = (res._embedded && res._embedded.contacts) || [];
let matched = null;
for (const c of list) {
  for (const cfv of (c.custom_fields_values || [])) {
    if (cfv.field_code !== 'PHONE') continue;
    for (const v of (cfv.values || [])) {
      const digits = String(v.value || '').replace(/\D/g, '').slice(-9);
      if (want && digits === want) { matched = c.id; break; }
    }
    if (matched) break;
  }
  if (matched) break;
}
return [{ json: { matched_contact_id: matched, candidates: list.length } }];

// Contacto vendedor: el reutilizado si hubo match, si no el recién creado (|| corto-circuita)
const matched = $('Resolve Vendor Match').first().json.matched_contact_id;
const vendor_contact_id = matched || $('Create Vendor Contact').first().json._embedded.contacts[0].id;
return [{ json: { vendor_contact_id, reused: Boolean(matched) } }];

const body = $input.first().json.body || $input.first().json;

let lead_id = null;
let status_id = null;

// Shape 1: manual curl { lead_id: 12345 }
if (body.lead_id) {
  lead_id = body.lead_id;
}

// Shape 2: Kommo form-encoded with literal bracket keys
// body['leads[status][0][id]'] = '12345'
if (!lead_id && body['leads[status][0][id]']) {
  lead_id = body['leads[status][0][id]'];
  status_id = Number(body['leads[status][0][status_id]']);
}

// Shape 3 (defensive): nested object if n8n ever parses it
if (!lead_id && body.leads && body.leads.status) {
  const change = Array.isArray(body.leads.status) ? body.leads.status[0] : body.leads.status['0'] || body.leads.status;
  if (change) {
    lead_id = change.id || change.lead_id;
    status_id = Number(change.status_id);
  }
}

if (!lead_id) {
  return [{ json: { skip: true, reason: 'no lead_id in payload' } }];
}

const EXPECTED_STATUS = 106758495;
if (status_id !== null && status_id !== EXPECTED_STATUS) {
  return [{ json: { skip: true, reason: 'status_id ' + status_id + ' != expected ' + EXPECTED_STATUS, lead_id } }];
}

return [{ json: { skip: false, lead_id: Number(lead_id), status_id } }];

const lead = $input.first().json;
const cfvMap = {};
for (const cfv of (lead.custom_fields_values || [])) {
  const v = cfv.values && cfv.values[0] && (cfv.values[0].value !== undefined ? cfv.values[0].value : cfv.values[0]);
  cfvMap[cfv.field_id] = v;
}

const submission_id = cfvMap[1375866];
const estado = cfvMap[1375868];

// Skip if the contract is already claimed/sent/signed. 'enviando' is the in-flight
// lock written BEFORE the Documenso side-effects, so retries that arrive after the
// claim are dropped even if the submission_id was not persisted yet.
if (estado === 'enviando' || estado === 'enviado_firma' || estado === 'firmado') {
  return [{ json: {
    already_sent: true,
    submission_id,
    estado,
    lead_id: lead.id,
    lead_name: lead.name,
    raw_lead: lead,
  } }];
}

return [{ json: { already_sent: false, raw_lead: lead } }];

