><table border="0" cellpadding="0" cellspacing="0"><tr><td style="width:40px;height:1px;background-color:#1F9D6E;font-size:1px;">&nbsp;</td><td style="padding:0 12px;font-family:Georgia,serif;font-size:11px;font-style:italic;color:#0F4A38;letter-spacing:3px;text-transform:uppercase;">Contratos</td><td style="width:40px;height:1px;background-color:#1F9D6E;font-size:1px;">&nbsp;</td></tr></table></td></tr><tr><td align="center" class="inner-pad" style="padding:24px 44px 0 44px;background-color:#ffffff;"><p style="font-family:Arial,Helvetica,sans-serif;font-size:10px;color:#4A7A66;letter-spacing:5px;text-transform:uppercase;font-weight:bold;margin:0 0 10px 0;">Firma pendiente</p><h1 class="head-title" style="font-family:Georgia,serif;font-size:40px;font-weight:normal;color:#0F1715;margin:0;line-height:1.05;letter-spacing:-1px;">Tu firma <em style="font-style:italic;color:#0F4A38;">${title_em}</em> el acuerdo.</h1></td></tr>${main_content}<tr><td align="center" class="footer-pad" style="background-color:#0A1512;padding:36px 44px;"><p style="font-family:Georgia,serif;font-size:28px;font-style:italic;color:#FFFFFF;margin:0;letter-spacing:0.5px;">Simarro <span style="color:#1F9D6E;font-style:italic;">Properties</span></p><table border="0" cellpadding="0" cellspacing="0" style="margin:12px 0;"><tr><td style="width:28px;height:1px;background-color:#1F9D6E;font-size:1px;">&nbsp;</td><td style="padding:0 10px;font-family:Georgia,serif;font-size:10px;color:#4A7A66;">&diams;</td><td style="width:28px;height:1px;background-color:#1F9D6E;font-size:1px;">&nbsp;</td></tr></table><p style="font-family:Arial,Helvetica,sans-serif;font-size:12px;color:#4A7A66;letter-spacing:1px;margin:0 0 6px 0;">Inmobiliaria &amp; Inversión</p><p style="margin:0;"><a href="https://simarroproperties.com" target="_blank" style="font-family:Arial,Helvetica,sans-serif;font-size:12px;color:#FFFFFF;text-decoration:none;font-weight:bold;letter-spacing:2px;text-transform:uppercase;border-bottom:1px solid #1F9D6E;padding-bottom:2px;">www.simarroproperties.com</a></p><p style="font-family:Arial,Helvetica,sans-serif;font-size:10px;color:#1F9D6E;letter-spacing:2px;text-transform:uppercase;margin:18px 0 0 0;line-height:1.7;">Documento gestionado mediante<br/>firma electrónica segura.</p></td></tr></table></center></body></html>`;
