const now = new Date();
const VENTANA_24H = 24 * 60 * 60 * 1000;
const VENTANA_4H = 4 * 60 * 60 * 1000;
const VENTANA_48H_POST = 48 * 60 * 60 * 1000;
const MARGEN = 15 * 60 * 1000;
const LIMPIEZA_72H = 72 * 60 * 60 * 1000;

const staticData = $getWorkflowStaticData('global');
staticData.enviados = staticData.enviados || {};

const cutoff = now.getTime() - LIMPIEZA_72H;
for (const k of Object.keys(staticData.enviados)) {
  if (staticData.enviados[k] < cutoff) delete staticData.enviados[k];
}

const tasks = [];
for (const item of $input.all()) {
  const arr = item.json && item.json._embedded && item.json._embedded.tasks;
  if (Array.isArray(arr)) tasks.push(...arr);
}

const resultados = [];
for (const task of tasks) {
  if (task.entity_type !== 'leads') continue;
  if (task.task_type_id !== 2) continue;
  if (!task.complete_till) continue;
  const fechaEvento = new Date(task.complete_till * 1000);
  const diffMs = fechaEvento - now;
  const diffPastMs = -diffMs;

  const es24h     = !task.is_completed && diffMs > (VENTANA_24H - MARGEN) && diffMs < (VENTANA_24H + MARGEN);
  const es4h      = !task.is_completed && diffMs > (VENTANA_4H  - MARGEN) && diffMs < (VENTANA_4H  + MARGEN);
  const es48hPost = diffPastMs > (VENTANA_48H_POST - MARGEN) && diffPastMs < (VENTANA_48H_POST + MARGEN);

  if (!es24h && !es4h && !es48hPost) continue;

  const tipo = es24h ? '24h' : es4h ? '4h' : '48h_post';
  const clave = `${task.id}_${tipo}`;
  if (staticData.enviados[clave]) continue;
  const leadId = task.entity_id;
  if (!leadId) continue;
  resultados.push({ leadId, tipoRecordatorio: tipo, taskId: task.id, taskText: task.text || '', clave });
}

return resultados.map(r => ({ json: r }));

