  const lineas = shown.map(m => {
    const t = TIPO[m.property_type] || 'Inmueble';
    const precio = m.price != null ? Number(m.price).toLocaleString('es-ES') + '€' : '';
    return `${t} en ${m.municipality || ''} ${precio}: ${m.url || ''}`;
  });
  let texto = lineas.join('  —  ');
  if (all.length > shown.length) texto += `  —  y ${all.length - shown.length} más.`;
  out.push({ json: {
    lead_id: Number(lead_id),
    texto,
    count: all.length,
    pares: all.map(m => ({ lead_id: Number(lead_id), idealista_id: m.idealista_id }))
  }});
}
return out;

