if (Array.isArray(resp)) {
  newId = resp[0] && resp[0].id;
} else if (resp && resp._embedded && resp._embedded.leads) {
  newId = resp._embedded.leads[0] && resp._embedded.leads[0].id;
} else if (resp && resp.id) {
  newId = resp.id;
} else if (resp && resp[0] && resp[0].id) {
  newId = resp[0].id;
}

if (!newId) {
  throw new Error('No new lead id returned. Got: ' + JSON.stringify(resp).slice(0, 300));
}

const note_body = [{
  entity_id: source.source_lead_id,
  note_type: 'common',
  params: {
    text: 'Trasvasado a pipeline Contratos. Lead nuevo: https://simarro.kommo.com/leads/detail/' + newId,
  },
}];

return [{
  json: {
    note_body,
    new_lead_id: newId,
    new_lead_url: 'https://simarro.kommo.com/leads/detail/' + newId,
    source_lead_id: source.source_lead_id,
    source_lead_name: source.source_lead_name,
  }
}];

const result = $input.first().json;
const ok = result.name === 'thumbnails';
const alreadyExists = result.error === 'The resource already exists';
return [{ json: {
  bucketCreated: ok,
  alreadyExisted: alreadyExists,
  result,
  status: ok ? 'created' : (alreadyExists ? 'already_existed' : 'error')
} }];
